interface Discount {
    double apply(double price);
}

class NoDiscount  implements Discount { public double apply(double p) { return p; } }
class TenPercent  implements Discount { public double apply(double p) { return p * 0.9; } }
class HalfPrice   implements Discount { public double apply(double p) { return p * 0.5; } }

class Cart {
    private Discount discount = new NoDiscount();
    void setDiscount(Discount d) { this.discount = d; }
    double total(double price)   { return discount.apply(price); }
}

public class Main {
    public static void main(String[] args) {
        Cart cart = new Cart();
        System.out.println(cart.total(100.0));
        cart.setDiscount(new TenPercent());
        System.out.println(cart.total(100.0));
        cart.setDiscount(new HalfPrice());
        System.out.println(cart.total(80.0));
    }
}
